// Generated by AI (UnitTest MCP)
//! Exponential half-life decay for edge weights.
//!
//! Effective weight `W_eff = W_base * 2^(-Δt_hours / half_life)`.
//! [`PRUNE_THRESHOLD`] is the built-in default; the startup-resolved
//! `DecayPolicy` owns the active threshold used by graph queries and pruning.

use serde::Serialize;

/// Built-in active-edge threshold when no project/environment override exists.
pub const PRUNE_THRESHOLD: f64 = 0.05;

/// Compute the time-decayed effective weight of an edge.
///
/// * `base` — stored base weight (0.0..=1.0).
/// * `half_life_hours` — hours for the weight to halve.
/// * `updated_at` — unix seconds of last reinforcement.
/// * `now` — current unix seconds.
pub fn effective_weight(base: f64, half_life_hours: f64, updated_at: i64, now: i64) -> f64 {
    if half_life_hours <= 0.0 {
        return base;
    }
    let dt_hours = (now - updated_at) as f64 / 3600.0;
    if dt_hours <= 0.0 {
        return base;
    }
    base * 2f64.powf(-dt_hours / half_life_hours)
}

/// Minimum reinforcements before an edge can earn a longer half-life.
pub const SIGNAL_MIN_COUNT: i64 = 3;
/// Minimum span (hours) the reinforcements must be spread across. Defeats
/// same-session spam: frequency alone is not signal (ADR-0005).
pub const SIGNAL_MIN_SPAN_HOURS: f64 = 48.0;
/// Cap on how far proven signal may stretch a half-life.
pub const SIGNAL_MAX_MULTIPLIER: f64 = 8.0;

/// Raw, deterministic evidence used to derive an edge's signal multiplier.
#[derive(Debug, Clone, Copy, Default, Serialize)]
pub struct SignalEvidence {
    pub reinforcement_count: i64,
    pub reinforcement_span_hours: f64,
    pub source_diversity: u32,
    pub consequence: bool,
    pub surprise: bool,
    pub structural_in_degree: u32,
    pub deliberate_attention: bool,
}

/// Map observable evidence to a bounded half-life multiplier.
pub fn signal_multiplier(evidence: SignalEvidence) -> f64 {
    let mut multiplier = 1.0;
    if evidence.reinforcement_count >= SIGNAL_MIN_COUNT
        && evidence.reinforcement_span_hours >= SIGNAL_MIN_SPAN_HOURS
    {
        multiplier += ((evidence.reinforcement_count as f64).log2() / 8.0).min(1.0);
    }
    multiplier += (evidence.source_diversity.saturating_sub(1).min(3) as f64) * 0.5;
    if evidence.consequence {
        multiplier += 2.5;
    }
    if evidence.surprise {
        multiplier += 0.75;
    }
    let centrality = (evidence.structural_in_degree as f64).ln_1p() / 16f64.ln_1p();
    multiplier += centrality.min(1.0);
    if evidence.deliberate_attention {
        multiplier += 1.25;
    }
    multiplier.min(SIGNAL_MAX_MULTIPLIER)
}

/// Graduate an edge's half-life by *proven signal*: reinforcement corroborated
/// across time earns a longer half-life, so it resists decay. One-offs (low
/// count) and same-session spam (narrow span) keep the base half-life — "decay
/// noise, not signal" (ADR-0005). A pure function of edge fields; nothing stored.
pub fn signal_half_life(
    base_half_life: f64,
    reinforcement_count: i64,
    first_seen: i64,
    updated_at: i64,
) -> f64 {
    let span_hours = (updated_at - first_seen) as f64 / 3600.0;
    base_half_life
        * signal_multiplier(SignalEvidence {
            reinforcement_count,
            reinforcement_span_hours: span_hours.max(0.0),
            ..SignalEvidence::default()
        })
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn fresh_edge_keeps_base_weight() {
        assert!((effective_weight(1.0, 24.0, 100, 100) - 1.0).abs() < 1e-9);
    }

    #[test]
    fn halves_after_one_half_life() {
        // 24h half-life, 24h elapsed -> 0.5
        let now = 24 * 3600;
        assert!((effective_weight(1.0, 24.0, 0, now) - 0.5).abs() < 1e-9);
    }

    #[test]
    fn decays_below_threshold_after_many_half_lives() {
        // 24h half-life, ~5 days elapsed -> well under 0.05
        let now = 5 * 24 * 3600;
        let w = effective_weight(1.0, 24.0, 0, now);
        assert!(w < PRUNE_THRESHOLD);
    }

    #[test]
    fn intent_outlives_execution() {
        let now = 7 * 24 * 3600;
        let intent = effective_weight(1.0, 168.0, 0, now);
        let exec = effective_weight(1.0, 24.0, 0, now);
        assert!(intent > exec);
    }

    #[test]
    fn signal_half_life_ignores_one_offs_and_spam() {
        // Too few reinforcements -> base half-life.
        assert_eq!(signal_half_life(24.0, 1, 0, 1_000_000), 24.0);
        // Enough count but all within a narrow span (spam) -> base half-life.
        let narrow = (SIGNAL_MIN_SPAN_HOURS as i64 - 1) * 3600;
        assert_eq!(signal_half_life(24.0, 10, 0, narrow), 24.0);
    }

    #[test]
    fn signal_half_life_extends_for_corroborated_signal() {
        // 3 reinforcements across 100h -> longer half-life, capped.
        let span = 100 * 3600;
        let hl = signal_half_life(24.0, 3, 0, span);
        assert!(hl > 24.0);
        assert!(hl <= 24.0 * SIGNAL_MAX_MULTIPLIER);
    }

    #[test]
    fn signal_multiplier_rejects_spam_and_prioritizes_consequence() {
        let spam = SignalEvidence {
            reinforcement_count: 400,
            reinforcement_span_hours: 1.0,
            ..SignalEvidence::default()
        };
        let isolated_failure = SignalEvidence::default();
        let resolved_failure = SignalEvidence {
            source_diversity: 3,
            consequence: true,
            surprise: true,
            structural_in_degree: 4,
            ..SignalEvidence::default()
        };

        assert_eq!(signal_multiplier(spam), 1.0);
        assert_eq!(signal_multiplier(isolated_failure), 1.0);
        assert!(signal_multiplier(resolved_failure) > 4.0);
    }

    #[test]
    fn signal_multiplier_rewards_independent_sources_and_stays_bounded() {
        let repetition = SignalEvidence {
            reinforcement_count: 12,
            reinforcement_span_hours: 96.0,
            ..SignalEvidence::default()
        };
        let diverse = SignalEvidence {
            source_diversity: 4,
            deliberate_attention: true,
            structural_in_degree: 100,
            consequence: true,
            surprise: true,
            ..repetition
        };

        assert!(signal_multiplier(diverse) > signal_multiplier(repetition));
        assert!(signal_multiplier(diverse) <= SIGNAL_MAX_MULTIPLIER);
    }
}
